INSERT INTO `webinar_quiz_questions` (`id`, `webinar_id`, `question_text`, `options`, `correct_option_index`, `display_order`, `created_at`) VALUES (1,5,'Какой основной подход помогает сделать классные часы «Разговоры о важном» интересными для учеников?','[\"Строго зачитывать текст из методических рекомендаций\", \"Использовать интерактивные формы работы и связь с реальной жизнью учеников\", \"Показывать только видеоролики без обсуждения\", \"Проводить занятие в форме контрольной работы\"]',1,1,'2026-02-18 05:25:36'),(2,5,'Какой формат проведения «Разговоров о важном» наиболее эффективен?','[\"Монолог учителя в течение 45 минут\", \"Письменный тест по теме занятия\", \"Дискуссия и диалог с учениками\", \"Просмотр документального фильма без обсуждения\"]',2,2,'2026-02-18 05:25:36'),(3,5,'Что является ключевым элементом успешного классного часа?','[\"Строгое соблюдение тайминга без вопросов\", \"Использование только печатных материалов\", \"Оценивание учеников за активность\", \"Учёт возрастных особенностей и интересов учеников\"]',3,3,'2026-02-18 05:25:36'),(4,5,'Какой сертификат можно получить после прохождения автовебинара?','[\"Диплом о переподготовке\", \"Аттестат о повышении квалификации\", \"Сертификат участника вебинара на 2 часа\", \"Удостоверение о присвоении категории\"]',2,4,'2026-02-18 05:25:36'),(5,5,'Как поддержать интерес учеников к тематике «Разговоров о важном» на протяжении всего учебного года?','[\"Повторять одни и те же темы каждую неделю\", \"Пропускать занятия, если тема кажется неинтересной\", \"Заменять классные часы на дополнительные уроки\", \"Варьировать формы работы и привлекать учеников к планированию\"]',3,5,'2026-02-18 05:25:36'),(6,7,'Какой из перечисленных способов применения нейросетей наиболее эффективен для подготовки учебных материалов?','[\"Полностью заменить учебник текстами, сгенерированными нейросетью\", \"Использовать нейросеть для создания дидактических карточек, рабочих листов и адаптированных текстов\", \"Копировать готовые ответы нейросети без проверки и редактирования\", \"Запретить ученикам знать о существовании нейросетей\"]',1,1,'2026-02-18 05:25:36'),(7,7,'Какой принцип является ключевым при использовании ИИ в работе педагога?','[\"ИИ должен полностью заменить учителя в процессе обучения\", \"Результаты работы нейросети не требуют проверки специалистом\", \"ИИ — это инструмент, который усиливает работу педагога, но не заменяет его\", \"Чем больше ИИ-инструментов используется на уроке, тем лучше результат\"]',2,2,'2026-02-18 05:25:36'),(8,7,'Как нейросети помогают в персонализации обучения?','[\"Выставляют оценки вместо учителя\", \"Заменяют индивидуальные консультации с учениками\", \"Позволяют создавать задания разного уровня сложности с учётом подготовки каждого ученика\", \"Автоматически переводят учеников в следующий класс\"]',2,3,'2026-02-18 05:25:36'),(9,7,'Какую рутинную задачу педагога нейросети могут помочь автоматизировать?','[\"Проведение родительских собраний\", \"Составление отчётов, проверка работ и формирование обратной связи\", \"Замена учителя на больничном\", \"Организация школьных экскурсий\"]',1,4,'2026-02-18 05:25:36'),(10,7,'Почему важно развивать у учеников навыки критической оценки информации, созданной нейросетями?','[\"Чтобы ученики никогда не пользовались нейросетями\", \"Чтобы ученики могли отличать достоверную информацию от ошибок ИИ и использовать технологии ответственно\", \"Чтобы полностью отказаться от традиционных учебников\", \"Чтобы ученики сами обучали нейросети\"]',1,5,'2026-02-18 05:25:36'),(11,8,'Чем буллинг отличается от обычного конфликта между детьми?','[\"Буллинг происходит только в старших классах\", \"Буллинг — это систематическое, повторяющееся агрессивное поведение при неравенстве сил\", \"Буллинг всегда включает физическое насилие\", \"Конфликт и буллинг — это одно и то же\"]',1,1,'2026-02-18 05:25:36'),(12,8,'Что должен сделать педагог в первую очередь при обнаружении буллинга в классе?','[\"Наказать агрессора и перевести его в другой класс\", \"Сообщить родителям жертвы и предложить перевод в другую школу\", \"Зафиксировать ситуацию, обеспечить безопасность жертвы и привлечь специалистов\", \"Провести классный час о дружбе и забыть о проблеме\"]',2,2,'2026-02-18 05:25:36'),(13,8,'Какой вид буллинга связан с намеренным исключением ребёнка из общения и совместной деятельности?','[\"Физический буллинг\", \"Вербальный буллинг\", \"Кибербуллинг\", \"Социальный буллинг (бойкот, изоляция)\"]',3,3,'2026-02-18 05:25:36'),(14,8,'Кто из специалистов школы играет ключевую роль в работе с эмоциональным состоянием ребёнка, подвергшегося травле?','[\"Учитель физкультуры\", \"Завуч по учебной работе\", \"Педагог-психолог\", \"Библиотекарь\"]',2,4,'2026-02-18 05:25:36'),(15,8,'Какой подход наиболее эффективен для профилактики буллинга в классе?','[\"Установить видеонаблюдение и строго наказывать нарушителей\", \"Не вмешиваться — дети сами разберутся\", \"Систематически формировать навыки эмпатии, уважения и создавать безопасную среду в коллективе\", \"Разделить класс на группы, чтобы конфликтующие дети не пересекались\"]',2,5,'2026-02-18 05:25:36'),(16,6,'Что является главной целью читательского марафона в образовательном учреждении?','[\"Увеличение количества прочитанных книг за учебный год\", \"Вовлечение семей в совместную читательскую деятельность с детьми\", \"Подготовка детей к олимпиадам по литературе\", \"Замена традиционных уроков чтения новым форматом\"]',1,1,'2026-02-26 03:33:36'),(17,6,'Какой формат взаимодействия с семьями наиболее эффективен при организации читательского марафона?','[\"Педагог составляет список книг, родители контролируют чтение дома\", \"Родители самостоятельно выбирают книги без участия педагога\", \"Совместные задания для родителей и детей с обратной связью от педагога\", \"Дети читают только в группе/классе под руководством воспитателя\"]',2,2,'2026-02-26 03:33:36'),(18,6,'Какой из перечисленных этапов является ключевым при подготовке читательского марафона?','[\"Подбор произведений с учётом возрастных особенностей и интересов детей\", \"Закупка большого количества новых книг для библиотеки\", \"Проведение родительского собрания с обязательной явкой\", \"Составление строгого графика чтения на каждый день\"]',0,3,'2026-02-26 03:33:36'),(19,6,'Каким образом читательские марафоны способствуют развитию ребёнка?','[\"Учат ребёнка читать быстрее и больше\", \"Заменяют необходимость посещения библиотеки\", \"Развивают речь, воображение и формируют устойчивый интерес к чтению через совместную деятельность с семьёй\", \"Готовят ребёнка исключительно к школьным контрольным по чтению\"]',2,4,'2026-02-26 03:33:36'),(20,6,'Что помогает поддерживать мотивацию семей на протяжении всего читательского марафона?','[\"Штрафы за невыполнение заданий в срок\", \"Промежуточные творческие задания и публичное признание достижений участников\", \"Ежедневные отчёты родителей перед педагогом\", \"Соревнование между семьями с выбыванием отстающих\"]',1,5,'2026-02-26 03:33:36');
